"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[65570],{40436(e,n,t){t.r(n),t.d(n,{assets:()=>f,contentTitle:()=>s,default:()=>d,frontMatter:()=>o,metadata:()=>i,toc:()=>c});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 21 and IAS 29/translation-of-a-hyperinflationary-f-21b5a63e3b","title":"Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29)","description":"March 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 21 and IAS 29/Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 21 and IAS 29","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-21-and-ias-29-41dd7e0b1f/translation-of-a-hyperinflationary-f-21b5a63e3b","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-21-and-ias-29-41dd7e0b1f/translation-of-a-hyperinflationary-f-21b5a63e3b","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"id":"translation-of-a-hyperinflationary-f-21b5a63e3b","title":"Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-21-and-ias-29-41dd7e0b1f/translation-of-a-hyperinflationary-f-21b5a63e3b","sidebar_position":3},"sidebar":"knowledgeSidebar","previous":{"title":"Presenting Comparative Amounts when a Foreign Operation first becomes Hyperinflationary (IAS 21 and IAS 29)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-21-and-ias-29-41dd7e0b1f/presenting-comparative-amounts-when--485b3c3e90"},"next":{"title":"Over Time Transfer of Constructed Good (IAS 23)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-23-borrowing-costs-c7e76e1ff5/over-time-transfer-of-constructed-go-aa70bd8985"}}');var a=t(74848),r=t(28453);let o={id:"translation-of-a-hyperinflationary-f-21b5a63e3b",title:"Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-21-and-ias-29-41dd7e0b1f/translation-of-a-hyperinflationary-f-21b5a63e3b",sidebar_position:3},s="Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29)",f={},c=[{value:"Do the restatement and translation effects meet the definition of an exchange difference?",id:"do-the-restatement-and-translation-effects-meet-the-definition-of-an-exchange-difference",level:2},{value:"How does an entity present any exchange difference arising from translating a hyperinflationary foreign operation?",id:"how-does-an-entity-present-any-exchange-difference-arising-from-translating-a-hyperinflationary-foreign-operation",level:2},{value:"Applying the requirements in IFRS Standards to the restatement and translation effects",id:"applying-the-requirements-in-ifrs-standards-to-the-restatement-and-translation-effects",level:2}];function h(e){let n={h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"translation-of-a-hyperinflationary-foreign-operationpresenting-exchange-differences-ias-21-and-ias-29",children:"Translation of a Hyperinflationary Foreign Operation\u2014Presenting Exchange Differences (IAS 21 and IAS 29)"})}),"\n",(0,a.jsx)(n.p,{children:"March 2020"}),"\n",(0,a.jsx)(n.p,{children:"The Committee received a request about the application of IAS 21 and IAS 29. In the fact pattern described in the request, the entity:"}),"\n",(0,a.jsx)(n.p,{children:"a. has a presentation currency that is not the currency of a hyperinflationary economy as defined in IAS 29;\nb. has a foreign operation with a functional currency that is the currency of a hyperinflationary economy as defined in IAS 29 (hyperinflationary foreign operation); and\nc. translates the results and financial position of the hyperinflationary foreign operation into its presentation currency in preparing its consolidated financial statements."}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 43 of IAS 21 requires an entity to restate the results and financial position of a hyperinflationary foreign operation applying IAS 29 before applying the translation method set out in paragraph 42 of IAS 21 (restate/translate approach). The application of the restate/translate approach may result in a change to the entity\u2019s net investment in the hyperinflationary foreign operation. This change would include two effects:"}),"\n",(0,a.jsx)(n.p,{children:"a. a restatement effect resulting from restating the entity\u2019s interest in the equity of the hyperinflationary foreign operation as required by IAS 29; and\nb. a translation effect resulting from translating the entity\u2019s interest in the equity of the hyperinflationary foreign operation (excluding the effect of any restatement required by IAS 29) at a closing rate that differs from the previous closing rate."}),"\n",(0,a.jsx)(n.p,{children:"To illustrate this using a simple example, assume at the beginning of the reporting period that an entity has a 100% interest in a hyperinflationary foreign operation that has a non-monetary asset of 1,000 in local currency (LC), no other assets and no liabilities. Therefore, the foreign operation has net assets (and equity) of LC1,000. The change in the general price index of the hyperinflationary economy during the reporting period is 200%. The entity could, for example, calculate:"}),"\n",(0,a.jsx)(n.p,{children:"a. the restatement effect as (LC1,000 \xd7 (1+200%) \u2013 LC1,000) \xd7 closing exchange rate. This calculation reflects the entity\u2019s interest in the equity of the hyperinflationary foreign operation of LC1,000, restated applying IAS 29, and reported in the entity\u2019s presentation currency; and\nb. the translation effect as (LC1,000 \xd7 closing exchange rate) \u2013 (LC1,000 \xd7 opening exchange rate). This calculation reflects the entity\u2019s interest in the equity of the hyperinflationary foreign operation of LC1,000 (excluding the effect of the restatement required by IAS 29) multiplied by the difference between the opening and closing exchange rates."}),"\n",(0,a.jsx)(n.p,{children:"The request asked how the entity presents the restatement and translation effects in its statement of financial position."}),"\n",(0,a.jsx)(n.h2,{id:"do-the-restatement-and-translation-effects-meet-the-definition-of-an-exchange-difference",children:"Do the restatement and translation effects meet the definition of an exchange difference?"}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 8 of IAS 21 defines an exchange difference as the difference \u2018resulting from translating a given number of units of one currency into another currency at different exchange rates\u2019. The Committee concluded that, in the fact pattern described in the request, either the translation effect alone meets the definition of an exchange difference, or the combination of the restatement and translation effects meets that definition."}),"\n",(0,a.jsx)(n.h2,{id:"how-does-an-entity-present-any-exchange-difference-arising-from-translating-a-hyperinflationary-foreign-operation",children:"How does an entity present any exchange difference arising from translating a hyperinflationary foreign operation?"}),"\n",(0,a.jsx)(n.p,{children:"The Committee observed that all requirements in IAS 21 that specify the recognition (or presentation) of exchange differences require an entity to recognise (or present) exchange differences in profit or loss or other comprehensive income (OCI). IAS 21 requires the recognition of exchange differences in profit or loss or OCI\u2014with no reference to equity \u2014because exchange differences meet the definition of income or expenses. Accordingly, the Committee concluded that an entity does not recognise exchange differences directly in equity."}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 7 of IAS 1 Presentation of Financial Statements states that components of OCI include \u2018gains and losses arising from translating the financial statements of a foreign operation\u2019. Paragraph 41 of IAS 21 explains that exchange differences arising from translating the financial statements of a non-hyperinflationary foreign operation are recognised in OCI\u2013\u2013and not in profit or loss\u2013\u2013because \u2018the changes in exchange rates have little or no direct effect on the present and future cash flows from operations\u2019. The Committee observed that this explanation is also relevant if the foreign operation\u2019s functional currency is hyperinflationary. Accordingly, the Committee concluded that an entity presents in OCI any exchange difference resulting from the translation of a hyperinflationary foreign operation."}),"\n",(0,a.jsx)(n.h2,{id:"applying-the-requirements-in-ifrs-standards-to-the-restatement-and-translation-effects",children:"Applying the requirements in IFRS Standards to the restatement and translation effects"}),"\n",(0,a.jsx)(n.p,{children:"The Committee concluded that, in the fact pattern described in the request, the entity presents:"}),"\n",(0,a.jsx)(n.p,{children:"a. the restatement and translation effects in OCI, if the entity considers that the combination of those two effects meets the definition of an exchange difference in IAS 21; or\nb. the translation effect in OCI, if the entity considers that only the translation effect meets the definition of an exchange difference in IAS 21. In this case, consistent with the requirements in paragraph 25 of IAS 29, the entity presents the restatement effect in equity."}),"\n",(0,a.jsx)(n.p,{children:"In the light of its analysis, the Committee considered whether to add a project on the presentation of exchange differences resulting from the restatement and translation of hyperinflationary foreign operations to its standard-setting agenda. The Committee has not obtained evidence that a project with that scope\u2014undertaken in isolation of other aspects of the accounting for hyperinflationary foreign operations\u2014would result in an\nimprovement in financial reporting that would be sufficient to outweigh the costs. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function d(e={}){let{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(h,{...e})}):h(e)}},28453(e,n,t){t.d(n,{R:()=>o,x:()=>s});var i=t(96540);let a={},r=i.createContext(a);function o(e){let n=i.useContext(r);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),i.createElement(r.Provider,{value:n},e.children)}}}]);